import{_ as e,o as p,c as t,j as r,a as b,a1 as _}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"先天打灰圣体·造化无极神功","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/功法/先天打灰圣体·造化无极神功.md","filePath":"4.资源分区/2.改造与功法/功法/先天打灰圣体·造化无极神功.md"}'),n={name:"4.资源分区/2.改造与功法/功法/先天打灰圣体·造化无极神功.md"};function s(o,a,d,l,i,c){return p(),t("div",null,[...a[0]||(a[0]=[r("h1",{id:"先天打灰圣体·造化无极神功",tabindex:"-1"},[b("先天打灰圣体·造化无极神功 "),r("a",{class:"header-anchor",href:"#先天打灰圣体·造化无极神功","aria-label":'Permalink to "先天打灰圣体·造化无极神功"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌032")])])],-1),_('<h1 id="先天打灰圣体·造化无极神功-1" tabindex="-1">先天打灰圣体·造化无极神功 <a class="header-anchor" href="#先天打灰圣体·造化无极神功-1" aria-label="Permalink to &quot;先天打灰圣体·造化无极神功&quot;">​</a></h1><p>先天打灰圣体·造化无极神功<br> 描述：此乃以血肉之躯，铸钢铁丛林的无上法门；习之者，注定与风沙为伍，与砖石结缘；练至大成，可肉身扛塔吊，监理如见真神。</p><p>搬沙境<br> 价格：D+600<br> 初入境，练搬沙，初入境，练搬沙，此乃打灰大道根基。习练者须每日搬运黄沙百袋，体悟“聚沙成塔”之理。</p><p>特性：【搬沙法】【风吹日晒】</p><p>搬沙法：你的负重/携带物品的上限翻倍。在进行力量相关检定时，你获得额外3DP修行加值。</p><p>风吹日晒：你获得了免疫不超过D级环境来源效果影响的能力。但由于风吹日晒的洗礼，你获得了一身古铜（黢黑）颜色的皮肤。</p><p>打灰境<br> 价格：C+1200<br> 描述：搬沙有成，方可接触“灰”之大道核心——水泥。<br> 特性：【桶遁术】【和泥劲】</p><p>桶遁术：“三十六计，提桶第一。”<br> 你的基础移动速度增加等同你的（传奇力量+传奇耐力+1）*5米。</p><p>和泥劲：你在进行攻击时，附带1点不可豁免的纠缠不良点数（环境来源）。你获得了1点基于天生防御的全伤害吸收。</p><p>运砖境<br> 价格：B+2400<br> 描述：身负巨力，可单手托砖如飞；心志坚定，任它寒来暑往，巍然不动（主要也是累得动不了）。此境主修“运砖”之巧劲与适应环境之“自在”。<br> 特性：【运砖功】【寒暑自在】</p><p>运砖功：你在搬沙法中取得的负重/携带物品上限翻倍的效果改为增加等同【传奇力量】倍。同时进入战斗后，每经过一轮，你都会获得1点基于天生防御的全伤害吸收与1点天生防御，取代和泥劲提供的全伤害吸收效果，上限为（传奇力量/2+本功法层数（d1c2b3a4）+传奇耐力/2）点。</p><p>寒暑自在：风吹日晒的环境免疫提升至B级，你获得等同自身传奇耐力*2点三豁免上的修行加值。</p><p>土木境<br> 价格：A+4800<br> 描述：钢筋为骨，水泥为肉，红盔护顶！此乃打灰圣体小成之象，举手投足间有搬山卸岭之威，寻常刀剑难伤，红盔所至，气场自生。<br> 特性：【钢筋铁骨水泥身】【红盔护体】</p><p>钢筋铁骨水泥身：你的肉身经过无数次微损伤和粉尘洗礼，终于发生了质变。</p><p>你使用一个整轮动作并支付4点意志力进行一次格挡，同时宣言【钢筋铁骨水泥身】，随后你在挥砍/穿刺/钝击中选择一种伤害性质，在接下来一场景中，你免疫首次受到的所选择的伤害，这是一个A级别变形来源的无敌效果。在那之后你受到的所选择的伤害减半计算。每轮开始时你可以使用自由动作切换选择的伤害性质至其他两种之一（但无敌效果不会因此而重置）。</p><p>红盔护体：那顶饱经风霜、可能还磕了个瘪的安全帽，象征着你的权威。</p><p>你在攻击时可以使被命中的目标以意志豁免伤害出目，失败则陷入持续一场景的A级别、幻象来源的【胁迫】状态，该【胁迫】状态会使其只能对队友进行攻击。若没有队友则可以正常对其他单位进行攻击。</p><p>转行法修<br> 价格：3S+19200<br> 描述：提桶跑路，考公上岸！<br> 效果：购买者立刻脱离主神空间，回归现实。<br> （注：这会使你失去对购买该资源的角色卡的操纵权）。</p><p>【下属技能】<br> 烂泥千斤坠<br> 价格：B+2000<br> 动作：整轮动作<br> 范围：50+传奇沉着*5米<br> 目标：见下<br> 消耗；3点意志力<br> 持续：一场景<br> 描述：若是打灰人心灰意懒、万念俱灰，体内“和泥劲”逆运失控，与天地间“丧气”共鸣，即可学会此招。习练者将放弃一切抵抗与行动，身心俱疲，如烂泥般瘫软在地，任由重力与自身“打灰圣体”之沉重发挥到极致。<br> 正所谓：“我烂故我在，千斤坠下来。任尔刀劈斧砍，我自躺平不睬。”<br> 效果：<br> 启动这一能力后，你先需要对范围内的敌对单位进行一次不附带任何招式的普通攻击检定，造成力场伤害。在攻击结束的一轮后，影响范围内的区域将形成一圈泥沼，在泥沼内的所有单位（包括你和友方单位），会陷入B级附身来源的困难地形影响。<br> ——<br> 该能力导致的困难地形一个区域性效果，会令受影响单位的移动距离降低为0，受影响单位无法进行冲锋，受影响载具无法进行加速，但以传送形式进行的移动不会受困难地形效果的影响。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const m=e(n,[["render",s]]);export{f as __pageData,m as default};
